const participants = $('Get Participants').all();
const scorecard = $('Get Scorecard').first().json[0];
const ruleFindings = $('Get Rule Findings').all().map(i => i.json);
const callId = $('Webhook').first().json.call_id;
const portalUrl = ($env.PORTAL_URL || 'https://daniel-call-analyzer.vercel.app') + '/calls/' + callId;

if (!scorecard) return [{ json: { __no_scorecard: true } }];

const score = parseFloat(scorecard.overall_score) || 0;
const scoreTier = score >= 8.5 ? 'EXCELLENT' : score >= 7 ? 'GOOD' : score >= 5 ? 'NEEDS_WORK' : 'POOR';

const compact_analysis = {
  call_id: callId,
  overall_score: score,
  score_tier: scoreTier,
  executive_summary: scorecard.summary || '',
  strengths: (scorecard.strengths || []).slice(0, 3),
  improvements: (scorecard.improvements || []).slice(0, 3),
  language_flags: ruleFindings
    .filter(f => f.severity === 'critical' || f.severity === 'warning')
    .slice(0, 5)
    .map(f => ({ rule: f.rule_key, value: f.value, severity: f.severity })),
  coaching_priorities: ruleFindings
    .filter(f => f.value && f.value.suggestion)
    .slice(0, 3)
    .map((f, i) => ({ priority: i + 1, area: f.rule_key, detail: f.value.suggestion }))
};

const emailTargets = participants
  .filter(p => p.json.team_members && p.json.team_members.email)
  .map(p => ({
    to: p.json.team_members.email,
    recipient_name: p.json.team_members.name || 'Team Member',
    compact_analysis_json: JSON.stringify(compact_analysis),
    portal_url: portalUrl
  }));

if (emailTargets.length === 0) return [{ json: { __no_recipients: true } }];
return emailTargets.map(t => ({ json: t }));

const item = $input.item.json;
const systemPrompt = 'You are an email formatter for WeBuildTrades. You receive a structured call analysis JSON and produce a professional HTML email for the management team. Rules: (1) inline CSS only - palette #1A1A2E headers, #E94560 warnings/red-flags, #0F9B8E wins/positives, #F5F5F5 section backgrounds, #FFFFFF body; (2) font Arial Helvetica sans-serif; (3) max-width 600px mobile-friendly; (4) score tier badge must be prominent - use large font and colour-coded background; (5) max 3 coaching priorities in email. Sections in order: [1] WeBuildTrades header with call date [2] Score badge (EXCELLENT/GOOD/NEEDS_WORK/POOR) plus numeric score [3] Executive summary 2-3 sentences [4] Key Wins - up to 3 bullets from strengths [5] Red Flags - up to 3 bullets from improvements [6] Top 3 Coaching Priorities with detail [7] Language Report showing banned words and tone [8] View Full Scorecard button linking to portal URL [9] Footer with unsubscribe note. Output ONLY the complete HTML email string. No JSON. No markdown. No preamble.';
const userPrompt = 'Convert the following call analysis JSON into a professional HTML email. Apply all design rules exactly.\n\nCALL ANALYSIS JSON:\n' + item.compact_analysis_json + '\n\nPORTAL URL FOR THIS CALL: ' + item.portal_url + '\nRECIPIENT NAME: ' + item.recipient_name + '\n\nReturn only the HTML string.';
return [{
  json: {
    to: item.to,
    recipient_name: item.recipient_name,
    compact_analysis_json: item.compact_analysis_json,
    groq_request_body: {
      model: 'llama-3.3-70b-versatile',
      max_tokens: 2048,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

const groqResponse = $input.item.json;
const prevData = $('Build Groq Request').item.json;
const html = groqResponse.choices && groqResponse.choices[0] && groqResponse.choices[0].message
  ? groqResponse.choices[0].message.content
  : '<p>Scorecard ready. View in portal.</p>';
const analysis = JSON.parse(prevData.compact_analysis_json || '{}');
return [{
  json: {
    to: prevData.to,
    overall_score: analysis.overall_score || '',
    html_body: html
  }
}];
